var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"카운터 여러분 안녕~ 이번 라이브는 루미의 단독 진행이야!","JPN":"カウンターのみんな～今回の配信はルミの単独進行よ！","ENG":"Hello Counters! This livestream is going to be Lumi's solo event!","TWN":"制裁者們大家好～這次的直播由魯米單獨進行喔！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"카운터즈 레거시가 서비스를 시작한 이후로 많은 일이 있었는데, 다들 잘 즐기고 있지?","JPN":"カウンターズ・レガシーがリリースされてから色んなことがあったけど、みんな楽しんでるかしら？","ENG":"A lot has happened since the launch of Counters Legacy. I hope you're all enjoying the game!","TWN":"制裁者的遺產自從開服以來發生了很多事情，大家都玩得開心嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"이번 라이브는 카운터즈 레거시의 새로운 소식을 전해주기 위해 찾아왔어!","JPN":"今日はカウンターズ・レガシーの新しいニュースをお届けするね！","ENG":"In this livestream, we'll be bringing you the latest news on Counters Legacy!","TWN":"這次開直播是為了公布制裁者的遺產的最新消息！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"오늘 나와 함께 해 주실 서가람 씨를 소개할게! 안녕하세요~","JPN":"今日のゲスト、カワセ・ヒカリさんを紹介するよ！　こんにちは～","ENG":"Joining me today is Ms. Seo Garam! Hello!","TWN":"先歡迎，今天和我一起進行的徐嘉蘭～"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"안녕하세요! 카운터즈 레거시의 개발을 담당하고 있는 서가람입니다.","JPN":"こんにちは、カウンターズ・レガシーの開発を担当しているカワセ・ヒカリです。","ENG":"Hello! I am Seo Garam, the main developer of Counters Legacy.","TWN":"你好！我是負責制裁者的遺產開發的徐嘉蘭。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L8_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"오픈 이후로 정말 많은 분들이 사랑해 주셨는데, 아직도 실감이 안 날 정도예요.","JPN":"オープンしてからたくさんの方に楽しんでいただいてますが、まだ実感が湧いていないです。","ENG":"So many people have been enjoying our game since launch, and it still feels surreal.","TWN":"自從開服以來，真的有很多人喜愛我們的遊戲，至今仍然沒什麼真實感呢。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그래서 조금이라도 빨리 보답하고 싶은 마음에, 이번 라이브를 준비하게 되었어요.","JPN":"なので少しでも早くお礼の気持ちを伝えたくて、今日の配信に出演することにしました。","ENG":"So, I wanted to repay the favor as quickly as I could, which led to this livestream.","TWN":"所以為了儘快報答大家的心意，這次準備了這場直播。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"오~ 어떤 보답을 준비하셨나요?","JPN":"お～お礼とは、何か準備したんですか？","ENG":"Ooh! What kind of rewards have you prepared for us?","TWN":"喔～你準備了什麼回報玩家呢？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L13_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"설마 누구도 예상 못 한 깜짝 이벤트를 준비하셨다던가?","JPN":"誰も予想できないようなサプライズイベントとか？","ENG":"Is it like a surprise event that no one expected?","TWN":"難道準備了誰也沒預料到的驚喜活動嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"네……?! 그건 대본에 없던……!","JPN":"え……！？　それは台本にない……！","ENG":"Huh...?! That's not in the script...!","TWN":"什……？！腳本上可沒寫這個……！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그, 그냥 적당히 넘겨야겠다…….","JPN":"て、適当にごまかそう……","ENG":"I-I should just gloss over this...","TWN":"那，那就隨便應付一下吧……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아하하, 나중에 정말 즐길 수 있는 분위기라면, 유저분들을 위해 즐거운 이벤트를 준비해 두겠습니다.","JPN":"あはは、そのうちタイミングを見計らって、ユーザーの皆さんのために楽しいイベントを用意します。","ENG":"Ah hah hah. I'll prepare a fun event for everyone when everyone gets in the mood.","TWN":"哈哈哈，我會為各位玩家準備有趣的活動，讓大家可以開心玩遊戲。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"오?! 농담으로 던진 말이었는데, 이렇게 된 거 기회는 반드시 잡아야겠죠?","JPN":"お！　半分冗談だったのに、このチャンス逃せませんね！","ENG":"Oh?! I was just joking, but I guess we must seize this opportunity, right?","TWN":"喔？！我只是開個玩笑，既然這樣，那就一定要抓住這個機會吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"시청자분들도 원하지 않아? 가람 씨가 준비한 이벤트는 무엇일지!","JPN":"視聴者の皆さんも楽しみよね？　ヒカリさんが用意するイベント！","ENG":"Don't you all want to know as well, chat? What Ms. Seo has in store for us?","TWN":"各位觀眾難道不想知道嗎？嘉蘭準備的活動是什麼呢！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"혹시~ 우리처럼 춤과 노래를 몰래 연습해 오셨다던가?","JPN":"ひょっとして～アタシたちみたいに歌とダンスをこっそり練習したとか？","ENG":"Let me guess. Have you... been secretly practicing singing and dancing?","TWN":"難道～你們也像我們一樣偷偷練習了舞蹈和歌曲嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아하하…… 일단 업데이트 관련 얘기부터 해볼까요……?","JPN":"あはは……まずはアップデートの話から始めましょうか……？","ENG":"Ah hah hah... Shall we talk about the update first...?","TWN":"哈哈哈……先說更新的事吧……？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"요새도 게임 업데이트 소식은 재미있게 전달하는구나.","JPN":"今もゲームのアップデートはこんな風に楽しくお知らせするのね。","ENG":"They still seem to deliver game updates in entertaining ways these days.","TWN":"最近也都有在報遊戲更新消息呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"보라가 설명하는 모습도 보고 싶었는데, 조금 아쉽네.","JPN":"シホちゃんが説明するところも見てみたかったけど、少し残念。","ENG":"I wanted to see Bora explain too, but I guess that will have to wait.","TWN":"本來還想看看寶拉慌忙解釋的樣子，有點可惜呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"과묵하니까…… 나는.","JPN":"寡黙だから……私は。","ENG":"That's because... I'm quiet.","TWN":"因為我……沉默寡言。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"어려워했었어…… 사회자가……","JPN":"苦手そうだった……司会の人。","ENG":"The host... found me difficult...","TWN":"做主持人……很難……"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"든든한 후배를 둬서 다행이네.","JPN":"頼もしい後輩がいてよかったわね。","ENG":"At least you have someone who's got your back.","TWN":"有給力的後輩真是太好了。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"열정이 많아. 회사에서도.","JPN":"すごく熱心。会社でも。","ENG":"She's got a lot of spirit. Even at work.","TWN":"在公司裡也充滿了熱情。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"후훗, 쉬는 시간마다 교무실에서 기획서를 만드시더라.","JPN":"ふふっ、休み時間も職員室で企画書を書いていたわ。","ENG":"Ha hah. I saw her working on her proposal in the teacher's office during every break.","TWN":"呵呵，每次休息時間都在教室裡寫企劃案呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"마침 마지막 업데이트에 대해 설명하려는 것 같네. 어떤 내용이니?","JPN":"ちょうど、最後のアップデートについて紹介をしようとしてるみたいね。どういう内容かしら？","ENG":"I think she's talking about the last part of the update now. What's it about?","TWN":"正好要說明最後的更新內容，是什麼呢？"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"응……?","JPN":"ん……","ENG":"Okay...","TWN":"嗯……?"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"다 끝났을 텐데……? 업데이트 소개.","JPN":"終わったはず……アップデートの紹介。","ENG":"She should be done... introducing the update.","TWN":"更新介紹……應該都結束了吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"자, 그럼 마지막으로 가람 씨가 자신한 큰 건에 대해 설명해 주시겠어요?","JPN":"さ、では最後に、ヒカリさんから自慢のビッグニュースです。どうぞ！","ENG":"Now, last but not least, can you tell us about the big surprise you have in store for us, Ms. Seo?","TWN":"那麼，最後請嘉蘭小姐解釋一下她所負責的大專案吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L43_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"네! 그라운드 원의 모두가 깜짝 놀랄만한 소식입니다!","JPN":"はい！　たぶんグラウンド・ワンの皆がびっくりすると思います！","ENG":"Yes! It's news that will surprise everyone in Ground One!","TWN":"是的！這是一個讓所有G1成員都大吃一驚的消息！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"지금까지 카운터가 아닌 일반 시민분들은 저희 시뮬레이션을 이용할 수 없어서 많이 아쉬우셨죠?","JPN":"今までカウンターじゃない一般市民の方は、私たちのシミュレーションを利用できず残念に思っていたはずです。","ENG":"I'm sure plenty of non-Counter people were upset that they couldn't participate in the simulations.","TWN":"到目前為止，非制裁者的普通市民無法使用我們的模擬系統，感到很遺憾吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L46_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"다음 업데이트부터는, 무려 모든 사람이 접속할 수 있게 될 거예요!","JPN":"ですが次のアップデートからはなんと、誰でもアクセスできるようになります！","ENG":"So, starting from the next update, everyone will be able to access it!","TWN":"從下次更新開始，所有人都可以登入了！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……뭐?","JPN":"………え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이건 관리국의 승인을 받은 최상급 아티팩트 <color=#ffd34c>오버로드</color>!","JPN":"これは管理局の承認を受けた最上級アーティファクトの<color=#ffd34c>オーバーロード</color>！","ENG":"This is a top-level Artifact approved by the Administration called, <color=#ffd34c>Overlord</color>!","TWN":"這是經過管理局批准的頂級神器<color=#ffd34c>超載</color>！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L50_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"저희 판도라는 이걸 카운터즈 레거시 안에서만 발현되도록 허가를 받는 조건으로 매입할 수 있었습니다.","JPN":"私たちパンドラは、カウンターズ・レガシーの中でのみ発現するという条件つきでこれを買い取ることができました。","ENG":"We at Pandora were able to purchase it on the condition that we only use it within Counters Legacy.","TWN":"之所以在我們潘朵拉能夠得到它，是因為我們承諾只會在制裁者的遺產中使用。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이 아티팩트는 자신이 동경하는 모습을 보여주는 물건이에요.\xA0\xA0\xA0","JPN":"このアーティファクトは、自分の憧れの姿を見せてくれます。\xA0\xA0\xA0","ENG":"This Artifact shows what you admire.\xA0\xA0\xA0","TWN":"這個神器會展示出你所憧憬的樣子。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"오버로드를 통해 유저들의 이상향을 보여주고 저희 카운터즈 레거시의 시스템으로 이미지화시켜 구현해 드리는 거죠.","JPN":"オーバーロードを通してユーザーに理想郷を見せ、私たちカウンターズ・レガシーのシステムでそれをイメージとして具現化するんです。","ENG":"So through Overlord, players can show us their ideals, and we can implement them into the Counters Legacy system.","TWN":"透過超載向玩家展示他們的烏托邦，並透過我們的制裁者的遺產系統將其形象化實現。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"자신이 직접 게임 캐릭터가 된다고 이해하시면 될 것 같습니다.","JPN":"自分が直接ゲームのキャラクターになると思うと理解しやすいかもしれません。","ENG":"In simple terms, you would become a game character yourself.","TWN":"可以理解為你自己變成了遊戲角色。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"자, 그라운드 원의 여러분! 모두 카운터즈 레거시에서 자신이 동경하던 꿈을 이뤄보세요!","JPN":"さ、グラウンド・ワンの皆さん！　カウンターズ・レガシーで憧れていた夢を叶えてみましょう！","ENG":"Now, everyone in Ground One! It's time to make your dreams come true in Counters Legacy!","TWN":"好了，G1的各位！在制裁者的遺產中實現你們所憧憬的夢想吧！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"}]`);export{e as default};